## ETH → USDC Swap with Smart Accounts

### Overview

The flow:
1. User grants a delegation to a session account to execute swaps on their behalf
2. Session account redeems the delegation to call a DEX router

---

### Installation

```bash
npm install @metamask/smart-accounts-kit viem
```

---

### Implementation

```typescript
import {
  Implementation,
  toMetaMaskSmartAccount,
  createDelegation,
  createExecution,
  ExecutionMode,
} from '@metamask/smart-accounts-kit'
import { DelegationManager } from '@metamask/smart-accounts-kit/contracts'
import {
  createPublicClient,
  createWalletClient,
  http,
  encodeFunctionData,
  parseEther,
  parseUnits,
} from 'viem'
import { sepolia } from 'viem/chains'
import { privateKeyToAccount } from 'viem/accounts'
import {
  createBundlerClient,
  createPaymasterClient,
} from 'viem/account-abstraction'

// ─── Config ────────────────────────────────────────────────────────────────

const UNISWAP_V3_ROUTER = '0x3bFA4769FB09eefC5a80d6E87c3B9C650f7Ae48E' // Sepolia
const WETH_ADDRESS      = '0xfFf9976782d46CC05630D1f6eBAb18b2324d6B14' // Sepolia WETH
const USDC_ADDRESS      = '0x1c7D4B196Cb0C7B01d743Fbc6116a902379C7238' // Sepolia USDC
const SWAP_AMOUNT       = parseEther('0.5')

// Uniswap V3 exactInputSingle ABI
const SWAP_ABI = [
  {
    name: 'exactInputSingle',
    type: 'function',
    inputs: [
      {
        name: 'params',
        type: 'tuple',
        components: [
          { name: 'tokenIn',           type: 'address' },
          { name: 'tokenOut',          type: 'address' },
          { name: 'fee',               type: 'uint24'  },
          { name: 'recipient',         type: 'address' },
          { name: 'amountIn',          type: 'uint256' },
          { name: 'amountOutMinimum',  type: 'uint256' },
          { name: 'sqrtPriceLimitX96', type: 'uint160' },
        ],
      },
    ],
    outputs: [{ name: 'amountOut', type: 'uint256' }],
  },
] as const

// ─── Clients ───────────────────────────────────────────────────────────────

const publicClient = createPublicClient({
  chain: sepolia,
  transport: http(),
})

const paymasterClient = createPaymasterClient({
  transport: http(process.env.PAYMASTER_URL!),
})

const bundlerClient = createBundlerClient({
  client: publicClient,
  transport: http(process.env.BUNDLER_URL!),
  paymaster: paymasterClient,
})

// ─── Accounts ──────────────────────────────────────────────────────────────

// User's smart account (delegator)
const userOwner = privateKeyToAccount(process.env.USER_PRIVATE_KEY as `0x${string}`)

const userSmartAccount = await toMetaMaskSmartAccount({
  client: publicClient,
  implementation: Implementation.Hybrid,
  deployParams: [userOwner.address, [], [], []],
  deploySalt: '0x',
  signer: { account: userOwner },
})

// Session account (delegate) — holds no funds, only signs
const sessionOwner = privateKeyToAccount(process.env.SESSION_PRIVATE_KEY as `0x${string}`)

const sessionSmartAccount = await toMetaMaskSmartAccount({
  client: publicClient,
  implementation: Implementation.Hybrid,
  deployParams: [sessionOwner.address, [], [], []],
  deploySalt: '0x',
  signer: { account: sessionOwner },
})

// ─── Step 1: Create Delegation ─────────────────────────────────────────────

const now    = Math.floor(Date.now() / 1000)
const expiry = now + 3600 // 1 hour

const delegation = createDelegation({
  to:          sessionSmartAccount.address,
  from:        userSmartAccount.address,
  environment: userSmartAccount.environment,
  // Allow calling the Uniswap router with up to 0.5 ETH
  scope: {
    type:     'functionCall',
    targets:  [UNISWAP_V3_ROUTER],
    selectors: ['exactInputSingle((address,address,uint24,address,uint256,uint256,uint160))'],
    valueLte: { maxValue: SWAP_AMOUNT }, // Allow sending ETH with the call
  },
  caveats: [
    // Only valid within the next hour
    { type: 'timestamp', afterThreshold: now, beforeThreshold: expiry },
    // One-time use
    { type: 'limitedCalls', limit: 1 },
    // Only the session account can redeem
    { type: 'redeemer', redeemers: [sessionSmartAccount.address] },
  ],
})

// ─── Step 2: Sign Delegation ───────────────────────────────────────────────

const signature = await userSmartAccount.signDelegation({ delegation })
const signedDelegation = { ...delegation, signature }

// ─── Step 3: Build Swap Execution ──────────────────────────────────────────

const swapCalldata = encodeFunctionData({
  abi:          SWAP_ABI,
  functionName: 'exactInputSingle',
  args: [
    {
      tokenIn:           WETH_ADDRESS,
      tokenOut:          USDC_ADDRESS,
      fee:               3000,                // 0.3% pool
      recipient:         userSmartAccount.address, // USDC goes back to user
      amountIn:          SWAP_AMOUNT,
      amountOutMinimum:  0n,                  // ⚠️ Set slippage in production!
      sqrtPriceLimitX96: 0n,
    },
  ],
})

const swapExecution = createExecution({
  target:   UNISWAP_V3_ROUTER,
  value:    SWAP_AMOUNT,       // Send 0.5 ETH with the call
  callData: swapCalldata,
})

// ─── Step 4: Redeem Delegation ─────────────────────────────────────────────

const redeemCalldata = DelegationManager.encode.redeemDelegations({
  delegations: [[signedDelegation]],
  modes:       [ExecutionMode.SingleDefault],
  executions:  [[swapExecution]],
})

const userOpHash = await bundlerClient.sendUserOperation({
  account: sessionSmartAccount,
  calls: [{
    to:   sessionSmartAccount.address,
    data: redeemCalldata,
  }],
})

// ─── Step 5: Wait for Receipt ──────────────────────────────────────────────

const receipt = await bundlerClient.waitForUserOperationReceipt({
  hash: userOpHash,
})

console.log('Swap complete:', receipt.receipt.transactionHash)
```

---

### Key Design Decisions

| Decision | Reason |
|----------|--------|
| `functionCall` scope | Restricts delegation to only the Uniswap router's `exactInputSingle` |
| `valueLte` caveat | Caps ETH sent to exactly 0.5 ETH — prevents draining the account
