  chain: sepolia,
  transport: http(),
})

const paymasterClient = createPaymasterClient({
  transport: http(process.env.PAYMASTER_URL!),
})

const bundlerClient = createBundlerClient({
  client: publicClient,
  transport: http(process.env.BUNDLER_URL!),
  paymaster: paymasterClient,
})

