  to:          sessionSmartAccount.address,
  from:        userSmartAccount.address,
  environment: userSmartAccount.environment,
  // Allow calling the Uniswap router with up to 0.5 ETH
  scope: {
    type:     'functionCall',
    targets:  [UNISWAP_V3_ROUTER],
    selectors: ['exactInputSingle((address,address,uint24,address,uint256,uint256,uint160))'],
    valueLte: { maxValue: SWAP_AMOUNT }, // Allow sending ETH with the call
