  target:   UNISWAP_V3_ROUTER,
  value:    SWAP_AMOUNT,       // Send 0.5 ETH with the call
  callData: swapCalldata,
})

// ─── Step 4: Redeem Delegation ─────────────────────────────────────────────

const redeemCalldata = DelegationManager.encode.redeemDelegations({
  delegations: [[signedDelegation]],
  modes:       [ExecutionMode.SingleDefault],
  executions:  [[swapExecution]],
})

const userOpHash = await bundlerClient.sendUserOperation({
  account: sessionSmartAccount,
  calls: [{
    to:   sessionSmartAccount.address,
    data: redeemCalldata,
  }],
})

// ─── Step 5: Wait for Receipt ──────────────────────────────────────────────

const receipt = await bundlerClient.waitForUserOperationReceipt({
  hash: userOpHash,
})

console.log('Swap complete:', receipt.receipt.transactionHash)
