    type: 'erc20TransferAmount',
    tokenAddress: USDC_ADDRESS,
    maxAmount: parseUnits('100', 6), // 100 USDC
  },
  caveats: [
    // Time-bound: only valid for 1 hour
    { type: 'timestamp', afterThreshold: now, beforeThreshold: expiry },
    // One-time use only
    { type: 'limitedCalls', limit: 1 },
    // Only the session account can redeem
    { type: 'redeemer', redeemers: [sessionSmartAccount.address] },
  ],
})

// User signs the delegation
const signature = await userSmartAccount.signDelegation({ delegation })
const signedDelegation = { ...delegation, signature }
```

### 5. Build the Swap Execution

The swap uses Uniswap V3's `exactInputSingle`. The session account redeems the delegation to approve USDC, then executes the swap.

